import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { ActivatedRoute, Router } from "@angular/router";
import { ApiService } from "src/app/shared/services/api.service";
import { ToastService } from "src/app/shared/services/toast.service";
import { SecurityDto, User } from "../auth/login/login.component";
import * as CryptoJS from "crypto-js";
import { SecurityPolicyService } from "src/app/shared/services/security-policy.service";
import { LoginService } from "src/app/shared/services/login.service";
import Swal from 'sweetalert2';
@Component({
  selector: "npr-forget-password",
  templateUrl: "./forget-password.component.html",
  styleUrls: ["./forget-password.component.scss"],
})
export class ForgetPasswordComponent implements OnInit {
  loginProcessing = false;
  passwordReset1: any;
  login = new Login();
  res: any;
  editable: boolean = false;
  finalpattern: string;
  responseMsg: any;
  responseError: any;
  passwordDTO: any;
  passwordStatus: boolean;
  msg: any;
  userId: string;
  lowerCase: string;
  security: SecurityDto;
  security1: SecurityDto;
  minPass: any;
  maxPass: any;
  ucase: any;
  lcase: any;
  num: any;
  splc: any;

  reactiveForm: FormGroup;
  passwordRegex: any;
  errorMsg: any = "";
  username: string;
  password: string;
  otp: string;

  hide = true;
  hideConfirm = true;
  modifyUserObject = new Login();
  variable: any;
  user: User;
  var: any;
  var1: any;
  isReadOnly: any;
  button1: any;
  spinnerbutton: boolean;
  button2: any;
  login1 = new Login();

  constructor(
    private router: Router,
    private route: ActivatedRoute,
    private apiService: LoginService,
    private fb: FormBuilder,

    private toastService: ToastService,
    private securityService: SecurityPolicyService
  ) {
    this.route.queryParams.subscribe((params) => {

      this.modifyUserObject.username = params.userId;
   
    });
  }

  ngOnInit() {
    this.isReadOnly = false;
    this.button2 = true;
    this.reactiveForm = this.fb.group({
      userId: new FormControl(""), // added
      otp: new FormControl("", [Validators.required]),
      password: new FormControl("", [
        Validators.required,
        Validators.compose([
          Validators.pattern(this.passwordRegex),
          Validators.maxLength(this.maxPass),
          Validators.minLength(this.minPass),
        ]),
      ]),
      confirmPassword: new FormControl("", [
        Validators.required,
        Validators.compose([
          Validators.pattern(this.passwordRegex),
          Validators.maxLength(this.maxPass),
          Validators.minLength(this.minPass),
        ]),
      ]),
    });

    this.userId = localStorage.getItem("userIdForChangePassword");
    let a, b;
    this.securityService.fetchSecurityPolicyService().subscribe((resp) => {
      this.security = resp;
      console.log(this.security);
      this.minPass = this.security.minPswdLength;
      this.maxPass = this.security.maxPswdLength;

      this.buildForm(this.minPass, this.maxPass);
      console.log(this.minPass, this.maxPass);
      console.log(this.security);
    });
    this.buildForm(
      this.minPass ? this.minPass : a,
      this.maxPass ? this.maxPass : b
    );
  }
  buildForm(a, b) {
    this.securityService.fetchSecurityPolicyService().subscribe((resp) => {
      this.security1 = resp;
      this.ucase = this.security1.pswdComplexUcase;
      this.lcase = this.security1.pswdComplexLcase;
      this.num = this.security1.pswdComplexNum;
      this.splc = this.security1.pswdComplexSplc;

      if (this.security1.pswdComplexUcase) {
        this.passwordRegex = "(?=[^A-Z]*[A-Z])";
        this.errorMsg = " UpperCase";
      }
      if (this.security1.pswdComplexLcase) {
        this.passwordRegex = this.passwordRegex + "(?=[^a-z]*[a-z])";
        if (this.errorMsg != null) {
          this.errorMsg = this.errorMsg + ", LowerCase";
        } else {
          this.errorMsg = this.errorMsg + " LowerCase";
        }
      }
      if (this.security1.pswdComplexNum) {
        this.passwordRegex = this.passwordRegex + "(?=[^0-9]*[0-9])";
        if (this.errorMsg != null) {
          this.errorMsg = this.errorMsg + ", Number";
        } else {
          this.errorMsg = this.errorMsg + " Number";
        }
      }
      if (this.security1.pswdComplexSplc) {
        this.passwordRegex = this.passwordRegex + "(?=[^!-@]*[!-@])";
        if (this.errorMsg != null) {
          this.errorMsg = this.errorMsg + ", Special Character";
        } else {
          this.errorMsg = this.errorMsg + " Special Character";
        }
      }

      this.passwordRegex =
        this.passwordRegex + ".{" + this.minPass + "," + this.maxPass + "}";
      this.errorMsg =
        "Password must contain atleast one " + this.errorMsg + ".";
      console.log(this.passwordRegex);


      this.reactiveForm = this.fb.group({
        userId: new FormControl(""),
        otp: new FormControl("", [Validators.required]),
        password: new FormControl("", [
          Validators.required,
          Validators.compose([
            Validators.pattern(this.passwordRegex),
            Validators.maxLength(this.maxPass),
            Validators.minLength(this.minPass),
          ]),
        ]),
        confirmPassword: new FormControl("", [
          Validators.required,
          Validators.compose([
            Validators.pattern(this.passwordRegex),
            Validators.maxLength(this.maxPass),
            Validators.minLength(this.minPass),
          ]),
        ]),
      });
    });

    console.log(this.minPass, this.maxPass);
    console.log("form", this.reactiveForm);
  }
  resetButton(){
    this.reactiveForm.reset();
  }
  reset(login: Login) {
    if (!login.username) {
     this.toastService.infoMessage("Enter User Id.", "");
      return;
    }

    var encryptedAES = CryptoJS.AES.encrypt(
      login.password,
      "@12#90!^*NPR*g&*()$34#$"
    );
    var USERNAME = CryptoJS.AES.encrypt(
      login.username,
      "@12#90!^*NPR*g&*()$34#$"
    );

    var data = encryptedAES.toString();
    var uname = USERNAME.toString();
    this.login1.password = data;
    this.login1.username = uname;

    this.login1.otp = this.otp;
    console.log(this.login1);
    this.spinnerbutton = true;
    this.apiService.forgetPassword(this.login1).subscribe((res) => {
      this.var1 = res;
      console.log(this.var1);
      if (this.var1) {
        this.spinnerbutton = false;
        if (this.var1[0] === "Login success.") {
          Swal.fire({text:
            "password Changed Successfully."}
           
          );
        } else {
          Swal.fire({text:this.var1[0]});
        }
      } else {
        this.spinnerbutton = false;

        Swal.fire({
         text: "Choose Other Password or otp is invalid."
        }
        );
      }
    });
  }
  getOtp(username) {
    this.loginProcessing = true;
    if (!username) {
      Swal.fire({text:"Enter User Id."});
      return;
    }

    var USERNAME = CryptoJS.AES.encrypt(username, "@12#90!^*NPR*g&*()$34#$");

    var uname = USERNAME.toString();
    console.log(uname);

    this.spinnerbutton = true;
    this.passwordReset1 = uname;
    console.log("uname", uname);
    this.apiService.getOtpForReset(this.passwordReset1).subscribe(
      (res) => {
        this.loginProcessing = false;
        this.var = res;
        if (this.var) {
          this.button1 = true;
          this.button2 = false;
          this.isReadOnly = true;
          this.spinnerbutton = false;
        } else {
          Swal.fire(
           {text: "Unable to find User details.Verify your userid."}
          );
          this.button1 = false;
          this.button2 = true;
          this.isReadOnly = true;
          this.spinnerbutton = false;
        }
      },
      (error) => {
        Swal.fire(
        {text:  "Server Error,Unable to connect server."}
        );
      }
    );
  }
  goHome() {
    this.router.navigate(["/login"]);
  }
  public changePassword(
    newPassword: string,
    confirmPassword: string,
    userId: string,
    otp
  ) {
    console.log(newPassword, confirmPassword, userId, otp);

    if (newPassword != confirmPassword) {
      Swal.fire({text:"Password Not Matched."});
    } else {
      this.loginProcessing = true;
      let encryptedAES = CryptoJS.AES.encrypt(
        newPassword,
        "@12#90!^*NPR*g&*()$34#$"
      );
      let USERNAME = CryptoJS.AES.encrypt(userId, "@12#90!^*NPR*g&*()$34#$");

      var data = encryptedAES.toString();
      let uname = USERNAME.toString();
      this.login.password = data;
      this.login.username = uname;
      this.login.otp = otp;
      console.log(this.login);
      this.apiService.forgetPassword(this.login).subscribe((res) => {
        this.loginProcessing = false;
        this.res = res;
        console.log(this.res);
        if (this.res) {
          // this.spinnerbutton = false;
          if (this.res[0] === "Login success.") {
            Swal.fire(
            { text: "Password Changed Successfully."}
            
            );
          }
          if (
            res[0] ==
            "You cannot use your previous password. Please choose another password"
          ) {
            Swal.fire(
              "You can not use your last " +this.security.pswdReuseAft +
                " passwords. Please choose another password.",
              ""
            );
          }
          if (res[0] == "OTP is invalid") {
            Swal.fire({text:"Otp is invalid."});
          }
          if (res[0] == "successfull") {
            Swal.fire(
              {text:"Password Changed Successfully."},
             
            );
          }
        } else {
          Swal.fire(
            {text:"Choose Other Password or otp is invalid."}
          );
        }
      });
    }
  }
}
export class Login {
  username: string;
  password: string;
  otp: string;
}
